import axios from 'axios';

// API base URL - 开发环境使用代理，避免CORS问题
const API_BASE_URL = '/api';

// 创建axios实例
const apiClient = axios.create({
  baseURL: API_BASE_URL,
  headers: {
    'Content-Type': 'application/json',
  },
  timeout: 30000
});

// 错误处理包装器
const safeApiCall = async (apiMethod, mockData = null) => {
  try {
    const response = await apiMethod();
    return response.data;
  } catch (error) {
    console.error('API 调用失败:', error);
    
    // 如果是开发环境并且提供了模拟数据，则返回模拟数据
    if (process.env.NODE_ENV === 'development' && mockData) {
      console.warn('使用模拟数据代替API响应');
      return mockData;
    }
    
    throw error;
  }
};

export default {
  // 获取小说列表
  async getNovelList() {
    const mockData = { novels: [] };
    return safeApiCall(() => apiClient.get('/novels'), mockData);
  },

  // 获取小说详情
  async getNovelDetail(novelId) {
    if (!novelId) {
      console.error('获取小说详情时没有提供novelId');
      throw new Error('小说ID不能为空');
    }
    
    const mockData = { id: novelId, title: '模拟小说', status: 'COMPLETED' };
    return safeApiCall(() => apiClient.get(`/novels/${novelId}`), mockData);
  },

  // 获取小说处理状态
  async getNovelStatus(novelId) {
    if (!novelId) {
      console.error('获取小说状态时没有提供novelId');
      throw new Error('小说ID不能为空');
    }
    
    const mockData = { status: 'PROCESSING', processedChapters: 5, totalChapters: 10 };
    return safeApiCall(() => apiClient.get(`/novels/${novelId}/status`), mockData);
  },

  // 上传小说
  async uploadNovel(formData) {
    if (!formData) {
      console.error('上传小说时没有提供数据');
      throw new Error('上传数据不能为空');
    }
    
    const mockData = { id: Math.floor(Math.random() * 1000), status: 'PROCESSING' };
    return safeApiCall(() => apiClient.post('/novels/upload', formData), mockData);
  },

  // 获取小说摘要分析
  async getSummaryAnalysis(novelId) {
    if (!novelId) {
      console.error('获取摘要分析时没有提供novelId');
      throw new Error('小说ID不能为空');
    }
    
    const mockData = { summary: '这是一个示例摘要分析。' };
    return safeApiCall(() => apiClient.get(`/novels/${novelId}/summary`), mockData);
  },

  // 获取小说章节列表
  async getChapterList(novelId) {
    if (!novelId) {
      console.error('获取章节列表时没有提供novelId');
      throw new Error('小说ID不能为空');
    }
    
    const mockData = { chapters: [] };
    return safeApiCall(() => apiClient.get(`/novels/${novelId}/chapters`), mockData);
  },

  // 获取标签分析
  async getTagAnalysis(novelId) {
    if (!novelId) {
      console.error('获取标签分析时没有提供novelId');
      throw new Error('小说ID不能为空');
    }
    
    const mockData = { tags: [] };
    return safeApiCall(() => apiClient.get(`/novels/${novelId}/tags`), mockData);
  },

  // 获取数据可视化
  async getVisualizations(novelId) {
    if (!novelId) {
      console.error('获取数据可视化时没有提供novelId');
      throw new Error('小说ID不能为空');
    }
    
    const mockData = { charts: [] };
    return safeApiCall(() => apiClient.get(`/novels/${novelId}/visualizations`), mockData);
  }
}
